// Some portions generated by Claude Code
package org.eclipse.rdf4j.query.algebra.evaluation.util;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.Random;

import org.eclipse.rdf4j.model.Literal;
import org.eclipse.rdf4j.model.Value;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.model.vocabulary.XSD;
import org.junit.jupiter.api.Test;

/**
 * The {@link ValueComparator} backs ORDER BY in multiple query engines that use different (stable) sort algorithms. For
 * the engines to produce identical row orders, the comparator must be a total order: antisymmetric and transitive for
 * every pair of values, including mixed xsd:date / xsd:dateTime literals whose XMLGregorianCalendar comparison is
 * INDETERMINATE for near-in-time pairs but determinate for far-apart ones.
 */
public class ValueComparatorTransitivityTest {

	private final ValueFactory vf = SimpleValueFactory.getInstance();

	/**
	 * Mirrors the LMDB differential fuzz dataset (seed 20260706): dates 2026-0X-1X interleaved with dateTimes
	 * 2026-06-2XT1X:30:00. The dates on the same day as a dateTime produce INDETERMINATE calendar comparisons.
	 */
	private List<Value> mixedDatesAndDateTimes() {
		List<Value> values = new ArrayList<>();
		values.add(vf.createLiteral("2026-01-15", XSD.DATE));
		values.add(vf.createLiteral("2026-03-14", XSD.DATE));
		values.add(vf.createLiteral("2026-06-21", XSD.DATE));
		values.add(vf.createLiteral("2026-06-24", XSD.DATE));
		values.add(vf.createLiteral("2026-06-25", XSD.DATE));
		values.add(vf.createLiteral("2026-07-12", XSD.DATE));
		values.add(vf.createLiteral("2026-09-18", XSD.DATE));
		values.add(vf.createLiteral("2026-06-20T10:30:00", XSD.DATETIME));
		values.add(vf.createLiteral("2026-06-21T11:30:00", XSD.DATETIME));
		values.add(vf.createLiteral("2026-06-24T14:30:00", XSD.DATETIME));
		values.add(vf.createLiteral("2026-06-25T15:30:00", XSD.DATETIME));
		values.add(vf.createLiteral("2026-06-25T18:30:00", XSD.DATETIME));
		values.add(vf.createLiteral("2026-06-29T19:30:00", XSD.DATETIME));
		return values;
	}

	/**
	 * Adds the coarser calendar types. A fallback that orders indeterminate pairs by raw datatype must be monotone in
	 * granularity, otherwise gYear/gYearMonth/date triples form comparison cycles.
	 */
	private List<Value> mixedTemporalFamily() {
		List<Value> values = mixedDatesAndDateTimes();
		values.add(vf.createLiteral("2025", XSD.GYEAR));
		values.add(vf.createLiteral("2026", XSD.GYEAR));
		values.add(vf.createLiteral("2027", XSD.GYEAR));
		values.add(vf.createLiteral("2026-03", XSD.GYEARMONTH));
		values.add(vf.createLiteral("2026-06", XSD.GYEARMONTH));
		values.add(vf.createLiteral("2026-08", XSD.GYEARMONTH));
		values.add(vf.createLiteral("10:30:00", XSD.TIME));
		values.add(vf.createLiteral("18:45:00", XSD.TIME));
		return values;
	}

	@Test
	public void testMixedDateDateTimeTotalOrderStrict() {
		assertTotalOrder(mixedDatesAndDateTimes(), true);
	}

	@Test
	public void testMixedDateDateTimeTotalOrderExtended() {
		assertTotalOrder(mixedDatesAndDateTimes(), false);
	}

	@Test
	public void testMixedTemporalFamilyTotalOrderStrict() {
		assertTotalOrder(mixedTemporalFamily(), true);
	}

	@Test
	public void testMixedTemporalFamilyTotalOrderExtended() {
		assertTotalOrder(mixedTemporalFamily(), false);
	}

	@Test
	public void testStableSortAlgorithmsAgreeOnMixedTemporalValues() {
		for (boolean strict : new boolean[] { true, false }) {
			ValueComparator cmp = new ValueComparator();
			cmp.setStrict(strict);

			List<Value> values = mixedTemporalFamily();
			Random random = new Random(20260706L);

			for (int round = 0; round < 100; round++) {
				List<Value> shuffled = new ArrayList<>(values);
				Collections.shuffle(shuffled, random);

				// TimSort, as used by the generic evaluator
				List<Value> timSorted = new ArrayList<>(shuffled);
				timSorted.sort(cmp);

				// binary insertion sort: a different stable algorithm, as a stand-in for the
				// merge sort used by the LMDB native engine
				List<Value> insertionSorted = insertionSort(shuffled, cmp);

				assertEquals(insertionSorted, timSorted,
						"stable sort algorithms must agree (strict=" + strict + ", round=" + round + ")");
			}
		}
	}

	private void assertTotalOrder(List<Value> values, boolean strict) {
		ValueComparator cmp = new ValueComparator();
		cmp.setStrict(strict);

		for (Value a : values) {
			for (Value b : values) {
				int ab = signum(cmp.compare(a, b));
				int ba = signum(cmp.compare(b, a));
				assertEquals(-ba, ab, () -> "antisymmetry violated (strict=" + strict + "): compare(" + label(a) + ", "
						+ label(b) + ")=" + ab + " but compare(" + label(b) + ", " + label(a) + ")=" + ba);
			}
		}

		for (Value a : values) {
			for (Value b : values) {
				int ab = signum(cmp.compare(a, b));
				for (Value c : values) {
					int bc = signum(cmp.compare(b, c));
					int ac = signum(cmp.compare(a, c));
					if (ab < 0 && bc < 0) {
						assertTrue(ac < 0, () -> "transitivity violated (strict=" + strict + "): " + label(a) + " < "
								+ label(b) + " and " + label(b) + " < " + label(c) + " but compare(" + label(a) + ", "
								+ label(c) + ")=" + ac);
					}
					if (ab == 0) {
						assertEquals(bc, ac, () -> "equality substitution violated (strict=" + strict + "): "
								+ label(a) + " == " + label(b) + " but compare(" + label(a) + ", " + label(c) + ")="
								+ ac + " while compare(" + label(b) + ", " + label(c) + ")=" + bc);
					}
				}
			}
		}
	}

	private static List<Value> insertionSort(List<Value> input, ValueComparator cmp) {
		List<Value> sorted = new ArrayList<>(input.size());
		for (Value value : input) {
			int lo = 0;
			int hi = sorted.size();
			while (lo < hi) {
				int mid = (lo + hi) >>> 1;
				if (cmp.compare(value, sorted.get(mid)) < 0) {
					hi = mid;
				} else {
					lo = mid + 1;
				}
			}
			sorted.add(lo, value);
		}
		return sorted;
	}

	private static int signum(int value) {
		return Integer.compare(value, 0);
	}

	private static String label(Value value) {
		Literal literal = (Literal) value;
		return "\"" + literal.getLabel() + "\"^^xsd:" + literal.getDatatype().getLocalName();
	}
}
